<?php declare(strict_types=1);
namespace App\Services;
use App\Repositories\UserRepository;
final class AuthService { public function __construct(private UserRepository $users,private RateLimitService $limits,private LogService $log){} public function login(string $email,string $password):bool{$key='login:'.hash('sha256',strtolower($email).($_SERVER['REMOTE_ADDR']??''));if($this->limits->exceeded($key,5,900))throw new \RuntimeException('Too many sign-in attempts. Try again in 15 minutes.');$u=$this->users->findByEmail($email);if(!$u||!password_verify($password,$u['password_hash'])){$this->limits->hit($key);$this->log->error('Failed login',['email'=>$email]);return false;}$this->limits->clear($key);session_regenerate_id(true);$_SESSION['user_id']=$u['id'];return true;} public function logout():void{$_SESSION=[];session_destroy();} public function check():bool{return isset($_SESSION['user_id']);} public function bootstrap(string $email,string $password):bool{if($this->users->count()>0)return false;$this->users->create($email,password_hash($password,PASSWORD_DEFAULT));return true;} }
